head.script:
scwin.onpageload = function() {

};

    //자회사물류/오더/통합매출입/확정후 전표조회 및 취소
    //330042/1111 로 로그인 , 청구부서 01383, 전표일자 20240530~20240630

    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.strPreDate = scwin.strCurDate.substring(0, 6) + "01";
    scwin.memJson = $c.data.getMemInfo();
	scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd)?'':scwin.memJson.coCd;    // 소속 자회사  
	scwin.vCoClsCd =$c.gus.cfIsNull(scwin.memJson.coClsCd)?'': scwin.memJson.coClsCd; //회계_회사구분('CO035' : 0:동부 EXPRESS)

    //console.log(scwin.memJson);     
	//-------------------------------------------------------------------------
 	// 화면로딩시
	//-------------------------------------------------------------------------
	scwin.f_OnLoad = function () {

		ica_qryConDtFm.setValue(scwin.strPreDate);
		ica_qryConDtTo.setValue(scwin.strCurDate);	
		//ed_cancelPostDt.setValue(scwin.strCurDate);
		ed_bilgLodeptCd.focus();
		acb_dcsnClsCd.setValue("4");

		$c.gus.cfEnableObj(ica_slipCloseYm, false);
		$c.gus.cfEnableObj(ica_taxCloseYm, false);

		acb_qryConKnd.setValue("전표번호");
		acb_delYn.setValue("0");

		scwin.f_setCompanyInfo();

		//f_Retrieve();
	};

scwin.onUdcCompleted = function() {
    //scwin.f_OnLoad();

    //ed_slipNo.hide();
    const codeOptions = [
        { grpCd: "FS500", compID: "acb_dcsnClsCd" }
        ,{ grpCd: "ZZ021", compID: "acb_apprvStsCd", opt :{"range" : "1,C"} }  //결재상태
        ,{ grpCd: "ZZ022", compID: "acb_apprvDocKndCd", opt :{"range" : "1,01"} }  //결재요청구분
    ]

    $c.data.setCommonCode(codeOptions,scwin.f_OnLoad);

};


