		scwin.f_resultPopEd = function (strCd,strNm,rtnList){
//console.log('scwin.f_resultPopEd~');
//console.log(rtnList);

			   if (rtnList != null ) {
			        if (rtnList[0] == "N/A") {
						return;
					}
					strCd.setValue(rtnList[0]);	// 코드
					strNm.setValue(rtnList[1]);	// 명
					strCd.hidVal = rtnList[0];  // 히든값
			    }else{
			    	strCd.setValue("");
					strNm.setValue("");
					strCd.hidVal = "";
				}

		};
  	//-------------------------------------------------------------------------
