	scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
	  	// 선언부
		var rtnList  = new Array();  // 공통POP-UP -> 요청화면 
		var clntNo   = ed_bilgClntNo.getValue();				
		var qryYear = scwin.strCurDate.substring(0,4);
console.log("scwin.f_openCommonPopUp~~"+disGubun);
		switch (disGubun) {

			case 1:
				// 청구부서  
		     	var param = ","+ed_coCd.getValue()+","+ed_coClsCd.getValue()+",0";

		 		//rtnList = udc_bilgClntNo.cfCommonPopUp('retrieveAcctDeptCdInfo6',ed_bilgLodeptCd.getValue().trim(),ed_bilgLodeptNm.getValue(),'T',null,null,null,null,param,null,null,null,null,null,null,null,null,null,qryYear); 
                udc_bilgLodeptCd.setSelectId('retrieveAcctDeptCdInfo6');
		 		rtnList = udc_bilgLodeptCd.cfCommonPopUp(scwin.udc_bilgLodeptCdCallback2,ed_bilgLodeptCd.getValue().trim(),ed_bilgLodeptNm.getValue(),'T',null,null,null,null,param,null,null,null,null,null,null,null,null,null,qryYear); 
               // scwin.f_resultPopEd(ed_bilgLodeptCd,ed_bilgLodeptNm,rtnList);
				break;
			case 2:
				var param=",,,"+ed_coCd.getValue();

                udc_bilgClntNo.setSelectId('retrieveClntList2');
		    	rtnList = udc_bilgClntNo.cfCommonPopUp(scwin.udc_bilgClntNoCallback,ed_bilgClntNo.getValue().trim(),ed_bilgClntNm.getValue(),'T',null,null,null,null,param,null,null,null,null); 

		    	//rtnList = cfCommonPopUp('retrieveClntList2',ed_bilgClntNo.getValue().trim(),ed_bilgClntNm.getValue(),'T',null,null,null,null,param,null,null,null,null); 
				//scwin.f_resultPopEd(ed_bilgClntNo,ed_bilgClntNm,rtnList);
				break;
	  		case 3:  		
				// 청구담당자코드 팝업		
				var param=",,,"+ed_coCd.getValue();
				//rtnList = cfCommonPopUp('retrieveEmpInfo3',pCode.trim(),pName,pClose,null,null,null,null,param,null,null,null,null,null,pAllSearch,null);	  				  			
				udc_modId.setSelectId('retrieveEmpInfo3');
				rtnList = udc_modId.cfCommonPopUp(scwin.udc_modIdCallback,pCode.trim(),pName,pClose,null,null,null,null,param,null,null,null,null,null,pAllSearch,null);	  				  			

				//$c.gus.cfSetReturnValue(rtnList, ed_modId, ed_modNm);  // 청구담당자코드, 청구담당자명
				break;

	  		default:
	  			break;
		}
	};

	//-------------------------------------------------------------------------
	// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
	//-------------------------------------------------------------------------
	scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
		// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
		if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
			return;

		// 짝이 되는 오브젝트의 값 제거
		$c.gus.cfClearPairObj(pairObj);

		// 검색어 세팅
		var pVal = $c.gus.cfGetValue(inObj);

		// inObj가 코드 필드일 경우 팝업
		if (isCode == null || isCode == true)
			scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
		// inObj가 코드명 필드일 경우 팝업
		else
			scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
	};

    scwin.udc_bilgLodeptCdCallback = function (rtnList) {
		if (rtnList != null ) {
            if (rtnList[0] != "N/A") {
                $c.gus.cfSetValue(ed_bilgLodeptCd,rtnList[0]);
                ed_bilgLodeptCd.hidVal = rtnList[0];
                $c.gus.cfSetValue(ed_bilgLodeptNm,rtnList[1]);
            }
        } else {
            $c.gus.cfSetValue(ed_bilgLodeptCd,"");
            ed_bilgLodeptCd.hidVal = "";
            $c.gus.cfSetValue(ed_bilgLodeptNm,"");
        }
};

scwin.udc_coCdCallback = function (rtnList) {
    // SET	 
    if(rtnList != null ) {
        if (rtnList[0] == "N/A") return; 

        if(ed_coCd.hidVal != rtnList[0] ) scwin.f_initObj();

        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        ed_coCd.hidVal = rtnList[0];  // 히든값
        ed_coClsCd.setValue(rtnList[1]);	// 회사구분    

    }else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.hidVal = ""; 
        ed_coClsCd.setValue("");
    }
};

scwin.udc_bilgLodeptCdCallback2 = function (rtnList) {
	scwin.f_resultPopEd(ed_bilgLodeptCd,ed_bilgLodeptNm,rtnList);
};

scwin.udc_bilgClntNoCallback = function (rtnList) {
