	scwin.f_FieldClear = function () {
		$c.gus.cfInitObjects(tbl_search,[ed_coCd,ed_coNm,ed_bilgLodeptCd,ed_bilgLodeptNm,acb_qryConKnd,ica_qryConDtFm,ica_qryConDtTo]);
